```typescript
// Get all audit logs for entity, ordered by timestamp
const history = await prisma.auditLog.findMany({
  where: { entityType, entityId },
  orderBy: { createdAt: 'asc' }
});

// Reconstruct state at any point in time
function reconstructStateAtTime(targetTime: Date) {
  const relevantLogs = history.filter(log => log.createdAt <= targetTime);
  let state = null;

  for (const log of relevantLogs) {
    if (log.operationType === 'Create') {
      state = log.afterState;
    } else if (log.operationType === 'Update') {
      state = { ...state, ...applyChanges(state, log) };
    } else if (log.operationType === 'Delete') {
      state = null;
    }
  }
  return state;
}
